const QUESTIONS_CCZT_C3 = [
  { id:60501, domain:3, level:1, question:"What is the primary purpose of a Software-Defined Perimeter (SDP)?", options:["It restricts resource access to authorized principals while hiding resources from all others","It encrypts data stored on protected application servers using rotating symmetric keys","It replaces the identity provider by issuing its own long-lived network access tokens","It accelerates web traffic by caching application responses at distributed edge nodes"], correct:0, explanation:"SDP grants access only to verified principals and conceals resources; encryption-at-rest and caching are unrelated." },
  { id:60502, domain:3, level:1, question:"In SDP terminology, what does the 'black cloud' concept describe?", options:["A public cloud region dedicated solely to storing encrypted security audit log data","Infrastructure that is invisible and unreachable to any client not yet authenticated","A backup data center that activates only after the primary site fully fails over","A segment used to quarantine devices that have failed their security posture checks"], correct:1, explanation:"The black cloud (dark infrastructure) hides resources until authentication; the others are unrelated infrastructure ideas." },
  { id:60503, domain:3, level:1, question:"Which three components define the standard CSA SDP architecture?", options:["A policy engine, a policy administrator, and a central network telemetry collector","An identity provider, a certificate authority, and a stateful perimeter firewall","An SDP controller, an Initiating Host client, and an Accepting Host gateway","A broker, a relay node, and an out-of-band administrative management console"], correct:2, explanation:"CSA defines controller, initiating host, and accepting host; the policy engine/administrator triad belongs to NIST ZTA." },
  { id:60504, domain:3, level:1, question:"In SDP, what is the role of the controller?", options:["It terminates all encrypted application traffic and forwards cleartext to the backend","It stores the only authoritative copy of each protected resource behind a bastion","It continuously scans the public internet for exposed ports owned by the company","It brokers trust by authenticating hosts and deciding which connections are permitted"], correct:3, explanation:"The controller is the trust broker authorizing connections; it does not terminate app traffic or store resource data." },
  { id:60505, domain:3, level:1, question:"What is the function of the Accepting Host (AH) in SDP?", options:["It is the gateway protecting resources that admits connections only from authorized hosts","It is the central directory holding every user's password hashes and group membership","It is the client agent installed on a laptop that requests access to a resource","It is the appliance that issues short-lived certificates to newly enrolled devices"], correct:0, explanation:"The AH gateway admits authorized IH connections; the IH client and CA are separate roles." },
  { id:60506, domain:3, level:1, question:"What is the function of the Initiating Host (IH) in SDP?", options:["It is the server-side endpoint that actually hosts the protected business application","It is the client that authenticates to the controller then initiates resource connections","It is the broker that evaluates access policy and signs each authorized session token","It is the logging service that records every connection attempt for later auditing"], correct:1, explanation:"The IH is the requesting client; the AH hosts resources and the controller evaluates policy." },
  { id:60507, domain:3, level:2, question:"What is Single Packet Authorization (SPA) used for in SDP?", options:["It compresses an entire authentication handshake into one packet to save bandwidth","It authorizes a single packet of application data per session for strict rate limiting","It lets a client prove authorization with one packet before any service port opens","It packages all session keys into one packet that the controller stores for later reuse"], correct:2, explanation:"SPA uses one authenticated packet to keep the gateway closed until a valid request; it is not about bandwidth or rate limiting." },
  { id:60508, domain:3, level:2, question:"How does an SDP gateway treat packets before SPA validation succeeds?", options:["It queues them in memory and replays them once a valid user later authenticates","It sends a TCP reset so scanners learn the host exists but its port is closed","It forwards them to a honeypot that records the source for threat-intelligence use","It silently drops them, leaving no open port and returning no response at all"], correct:3, explanation:"Default-drop means unauthorized packets are discarded silently; any reply would reveal the host." },
  { id:60509, domain:3, level:2, question:"Which technique is commonly embedded in an SPA packet to prevent forgery?", options:["An HMAC computed over the packet using a key shared with the controller","A full RSA-4096 signature over the payload plus a notarized timestamp chain","A symmetric cipher applied to the source IP to obscure the client's location","A reversible base64 encoding of the username so the gateway can decode it"], correct:0, explanation:"An HMAC authenticates the SPA packet; base64 is not protection and a heavy RSA chain is not specified." },
  { id:60510, domain:3, level:2, question:"How does SPA typically resist replay attacks?", options:["It encrypts the packet twice with two distinct keys held by the controller alone","It includes a time-based value like a TOTP or counter so stale packets are rejected","It requires the client to solve a proof-of-work puzzle before the packet is accepted","It mandates a complete mutual-TLS handshake before the single packet is transmitted"], correct:1, explanation:"A time/counter element makes captured packets stale; mTLS occurs after SPA, not before." },
  { id:60511, domain:3, level:1, question:"What posture does an SDP gateway adopt by default toward unauthenticated traffic?", options:["Default-allow, permitting traffic until a rule explicitly blocks a known-bad source","Default-log, accepting traffic for inspection while recording it for later review","Default-drop, denying and discarding everything until access is explicitly authorized","Default-redirect, sending unknown traffic to a captive portal for self-service signup"], correct:2, explanation:"SDP gateways are default-drop; allow-by-default or redirect contradicts cloaking." },
  { id:60512, domain:3, level:2, question:"What role does mutual TLS play after SPA in an SDP connection?", options:["It lets the server skip verifying the client because SPA already proved its identity","It encrypts only the server-to-client direction to protect downloaded application data","It replaces the controller so the two hosts can negotiate policy directly themselves","It authenticates client and server to each other before any data is allowed to flow"], correct:3, explanation:"mTLS provides bidirectional authentication after SPA; SPA does not remove the server's verification step." },
  { id:60513, domain:3, level:2, question:"SDP strengthens access decisions by validating which two factors together?", options:["The user's identity and the posture or identity of the device being used","The user's identity and the geographic distance to the nearest gateway node","The device MAC address and the current load on the destination application server","The source port number and the time elapsed since the last successful login event"], correct:0, explanation:"SDP binds user authentication to device validation; MAC and server load are weak or irrelevant." },
  { id:60514, domain:3, level:2, question:"How does SDP differ fundamentally from a traditional VPN?", options:["SDP demands hardware tokens for everyone, while a VPN can rely on passwords alone","SDP grants access per resource after authorization, while a VPN often exposes a network","SDP works only in a single data center, while a VPN is designed for the public cloud","SDP uses weaker ciphers but compensates with much faster initial connection setup"], correct:1, explanation:"SDP gives least-privilege per-resource access; VPNs grant broad network access. The cipher/location claims are false." },
  { id:60515, domain:3, level:2, question:"Why does SDP limit lateral movement better than a flat VPN-connected network?", options:["It assigns every connected client the same subnet so traffic is easier to monitor","It disables internal encryption so intrusion detection can read all packet contents","Each session reaches only its specific resource, never the broader internal network","It routes each connection over the public internet to add geographic separation"], correct:2, explanation:"Per-resource micro-tunnels block reaching other systems; a shared subnet would enable lateral movement." },
  { id:60516, domain:3, level:3, question:"What is the correct high-level CSA SDP connection sequence?", options:["IH-to-AH first, then the AH asks the controller whether that connection was allowed","AH-to-controller first, then the controller pushes a user list to every IH client","IH-to-AH and controller-to-IH at once, with the AH arbitrating any policy conflicts","Controller onboarding, IH-to-controller, controller-to-AH, then the IH-to-AH connection"], correct:3, explanation:"The CSA sequence onboards hosts, authenticates the IH, programs the AH, then permits IH-to-AH; other orders break the model." },
  { id:60517, domain:3, level:3, question:"After the controller authorizes an IH, what does it instruct the AH to do?", options:["Accept an imminent connection from that one specific authorized initiating host","Broadcast its presence to all clients so they can discover the protected resource","Open every port temporarily so the controller can verify the service is healthy","Forward the client's credentials back to the controller for a second verification"], correct:0, explanation:"The controller tells the AH to expect the named IH; broadcasting or opening all ports defeats cloaking." },
  { id:60518, domain:3, level:1, question:"Which SDP deployment model connects an endpoint client directly to a protecting gateway?", options:["The gateway-to-gateway model linking two protected networks over untrusted transit","The client-to-gateway model","The server-to-server model securing automated machine-to-machine east-west traffic","The client-to-server-to-client model brokering a session between two user devices"], correct:1, explanation:"Client-to-gateway has an IH client reach an AH gateway; the others are network-to-network or peer scenarios." },
  { id:60519, domain:3, level:1, question:"Which SDP deployment model best secures east-west traffic between two services?", options:["The client-to-gateway model where a remote laptop reaches an internal app server","The client-to-server-to-client model connecting two human users via a broker","The server-to-server model","The gateway-to-gateway model joining two corporate sites over a shared backbone"], correct:2, explanation:"Server-to-server secures service-to-service connections; the others involve end users or whole networks." },
  { id:60520, domain:3, level:2, question:"The gateway-to-gateway SDP model is most analogous to which traditional construct?", options:["A reverse proxy that load-balances inbound web requests across a server farm","A captive portal that authenticates guests before granting limited internet access","A jump box that administrators log into before reaching production servers","A site-to-site tunnel between networks, but with cloaking and per-flow authorization"], correct:3, explanation:"Gateway-to-gateway resembles a site-to-site link with SDP cloaking; proxies, portals, and jump boxes differ." },
  { id:60521, domain:3, level:2, question:"In the client-to-server-to-client SDP model, what is connected?", options:["Two end-user devices brokered through an intermediary so peers expose no direct ports","A user device to a protected database that then replicates to a second database","Two gateways that each shield a different subnet of internal application servers","A client to an external SaaS provider that proxies the session to a partner network"], correct:0, explanation:"Client-to-server-to-client links two peer clients via a broker; the others describe gateway or data-tier topologies." },
  { id:60522, domain:3, level:2, question:"Why does SDP effectively neutralize remote port-scanning reconnaissance?", options:["It randomizes the listening port every few seconds so scanners cannot keep pace","Cloaked gateways never reply to unauthorized probes, so scanners find nothing to map","It returns false open-port banners to mislead and exhaust the scanning process","It rate-limits each scanning source until the scan times out and gives up"], correct:1, explanation:"Silent non-response makes hosts invisible; banner spoofing or rate-limiting still reveals existence." },
  { id:60523, domain:3, level:2, question:"How does SDP help mitigate denial-of-service attacks on protected applications?", options:["It mirrors the application across regions so attack traffic is spread out evenly","It negotiates with the ISP to blackhole the attacker's prefix within a few seconds","Unauthenticated packets are dropped at the gateway before reaching the application","It throttles legitimate users equally so the application's total load stays constant"], correct:2, explanation:"Dropping unauthorized traffic at the perimeter keeps floods off the app; SDP is not a CDN or ISP blackhole." },
  { id:60524, domain:3, level:2, question:"How does SDP reduce exposure to exploitation of unpatched server software?", options:["It automatically applies vendor patches the moment they are published by the vendor","It rewrites malicious payloads inline so known exploit signatures are neutralized","It runs each service in a disposable container that is rebuilt after every request","Vulnerable services are unreachable to attackers who cannot first authenticate"], correct:3, explanation:"Cloaking makes vulnerable services unreachable without authorization; SDP does not patch or rewrite payloads." },
  { id:60525, domain:3, level:2, question:"How does SDP help limit the impact of stolen user credentials?", options:["Valid credentials still fail unless the request also comes from an authorized device","It detects and revokes any credential the instant it appears for sale on the dark web","It encrypts stored passwords so attackers cannot read them after a database breach","It forces every user to change their password automatically after each single login"], correct:0, explanation:"Binding access to device posture makes stolen credentials alone insufficient; the others are separate controls." },
  { id:60526, domain:3, level:2, question:"How does an SDP gateway reduce network-layer exposure to web attacks like SQL injection?", options:["It parses each SQL statement and rejects any query that modifies more than one row","Only authorized clients can reach the app, shrinking who can attempt injection","It swaps the backend database for a read-only copy to block all write attempts","It strips all user-supplied input from requests before they reach the application"], correct:1, explanation:"SDP limits who can send requests at all; it is not a WAF that parses SQL or strips input." },
  { id:60527, domain:3, level:2, question:"How does mutual TLS in SDP help defend against man-in-the-middle attacks?", options:["It pins the session to one physical switch port that no other device may ever use","It encrypts only the handshake while leaving application data in cleartext for speed","Both endpoints verify each other's certificates, blocking impersonation by a middle party","It routes traffic through three relays so no single relay can read the entire path"], correct:2, explanation:"Mutual certificate checks stop endpoint impersonation; relaying and partial encryption are unrelated." },
  { id:60528, domain:3, level:2, question:"Which one-time-password mechanism is often referenced as an input to SPA?", options:["A static API key embedded in the client binary and rotated only once each year","A challenge nonce the server must email to the user before every connection","A hardware token that prints a single permanent code on the device's label","TOTP, a time-based code derived from a shared secret and the current time"], correct:3, explanation:"TOTP provides the time-varying value used in SPA; static keys or permanent codes give no replay resistance." },
  { id:60529, domain:3, level:2, question:"Why is SDP useful for securing IoT deployments?", options:["It cloaks constrained devices so they are not exposed to internet scanning attempts","It installs a full endpoint-detection agent on every sensor regardless of its memory","It guarantees device firmware is patched before any of its traffic is ever permitted","It gives every device a public IP so it can be reached securely from anywhere at all"], correct:0, explanation:"SDP hides IoT endpoints from scanning even when constrained; heavy agents or public IPs are impractical." },
  { id:60530, domain:3, level:2, question:"Why is SDP well suited to cloud and hybrid environments?", options:["It requires all workloads in one cloud provider to keep the controller logic simple","It enforces identity-based access independent of network location or perimeter boundaries","It depends on fixed corporate IP ranges, which cloud autoscaling reliably preserves","It mandates a physical hardware appliance in every cloud region to terminate tunnels"], correct:1, explanation:"SDP decouples access from network location, fitting dynamic cloud/hybrid; it needs no single-cloud or fixed IPs." },
  { id:60531, domain:3, level:2, question:"Why is the SDP controller a high-value target requiring hardening?", options:["It stores every protected resource's data, so its loss would erase all applications","It performs all network encryption, so its failure would decrypt existing sessions","As the trust broker, its compromise could let an attacker authorize illicit connections","It is the only device with a public IP, so attackers always reach it first by default"], correct:2, explanation:"A compromised trust broker could grant unauthorized access; it does not store data or decrypt all sessions." },
  { id:60532, domain:3, level:1, question:"What is the relationship between SDP and ZTNA?", options:["ZTNA is an older protocol that SDP was created specifically to deprecate and replace","SDP and ZTNA are competing standards that cannot run in the same environment at once","ZTNA is a hardware category while SDP refers only to a cloud-based billing model","SDP is a foundational architecture that ZTNA solutions commonly implement to broker access"], correct:3, explanation:"ZTNA frequently builds on SDP concepts; they are complementary, not competing." },
  { id:60533, domain:3, level:2, question:"What distinguishes service-initiated ZTNA from endpoint-initiated ZTNA?", options:["Service-initiated uses an outbound app connector and needs no agent on the endpoint","Service-initiated always requires a heavy agent installed on each user's device first","Endpoint-initiated keeps the application directly exposed to the public internet always","Endpoint-initiated can only be used for server-to-server machine-to-machine traffic"], correct:0, explanation:"Service-initiated ZTNA uses an outbound connector and is often agentless; endpoint-initiated uses a device agent." },
  { id:60534, domain:3, level:2, question:"How do SDP and ZTNA compare to a traditional VPN concentrator for remote access?", options:["They require users to be physically on-site before any remote tunnel can be set up","They grant per-application access and cloak resources rather than placing users on a network","They expose the same broad network range but merely add stronger encryption ciphers","They remove all need for authentication because the tunnel itself proves identity"], correct:1, explanation:"SDP/ZTNA give cloaked per-app access unlike VPNs that put users on the network; they keep authentication." },
  { id:60535, domain:3, level:2, question:"How does SDP enforce least privilege at the network layer?", options:["It assigns each user the broadest role first and then trims permissions over time","It grants full subnet access but logs everything so misuse can be detected later","It opens connectivity only to the specific resources a principal is authorized to use","It relies on the application itself to reject requests after the network admits them"], correct:2, explanation:"SDP limits reachability to authorized resources only; broad-then-trim or app-only enforcement does not." },
  { id:60536, domain:3, level:2, question:"What do 'pre-authentication' and 'pre-authorization' mean in SDP?", options:["A user gets temporary access first and is verified only after the transfer ends","The controller pre-shares all resource passwords so later authentication is skipped","Resources stay open but log access so authorization can be reconstructed afterward","A host must prove identity and be approved before any path to a resource is opened"], correct:3, explanation:"SDP authenticates and authorizes before opening a path; granting access first contradicts the model." },
  { id:60537, domain:3, level:1, question:"In an SDP, which component is responsible for evaluating policy and authorizing host connections?", options:["The SDP controller acting as the trust broker for the architecture","The Accepting Host gateway that fronts the protected resource","The Initiating Host client running on the user's endpoint device","The certificate authority that signs device enrollment requests"], correct:0, explanation:"The controller is the trust broker that authorizes connections; the AH and IH are data-plane endpoints." },
  { id:60538, domain:3, level:1, question:"In an SDP, which component sits in front of and protects the target resource?", options:["The SDP controller serving as the central policy decision point","The Accepting Host gateway","The Initiating Host client that originates the access request","The directory service that stores user and group attributes"], correct:1, explanation:"The AH gateway protects the resource and admits authorized clients; the controller decides policy and the IH requests access." },
  { id:60539, domain:3, level:1, question:"In an SDP, which component initiates the request for access to a protected resource?", options:["The Accepting Host gateway guarding the requested resource","The SDP controller that brokers trust across the deployment","The Initiating Host client","The logging collector that aggregates connection telemetry"], correct:2, explanation:"The IH client initiates access; the AH protects the resource and the controller authorizes." },
  { id:60540, domain:3, level:2, question:"Which SDP component does an Initiating Host contact first to begin gaining access?", options:["The Accepting Host gateway, which it reaches directly over an open port","The target application server, which then relays the request to the controller","A peer Initiating Host, which vouches for the new connection request","The controller, which authenticates the host before any resource path exists"], correct:3, explanation:"The IH authenticates to the controller first; it cannot reach the AH until the controller authorizes." },
  { id:60541, domain:3, level:2, question:"Which SDP component receives instructions about which initiating hosts to accept?", options:["The Accepting Host gateway, programmed by the controller after authorization","The Initiating Host client, told directly by the resource it wants to reach","The identity provider, which then opens the firewall on the gateway's behalf","The DNS resolver, which selectively answers only authorized lookups"], correct:0, explanation:"The controller programs the AH to accept a specific IH; the IH and DNS do not perform this role." },
  { id:60542, domain:3, level:2, question:"How does SDP help mitigate OWASP Top Ten web application threats?", options:["It inspects HTTP bodies and rewrites every request to a safe canonical form first","By cloaking resources so fewer attackers can reach the app to attempt them","It automatically generates a patch for each OWASP category as soon as it is published","It blocks the application from making any outbound calls that could leak sensitive data"], correct:1, explanation:"SDP reduces exposure by hiding resources from unauthorized access; the distractors describe controls SDP does not perform." },
  { id:60543, domain:3, level:2, question:"How does SDP help mitigate cross-site scripting (XSS) opportunities?", options:["It sanitizes every HTML response by stripping all embedded JavaScript before delivery","It disables client-side scripting entirely in the browsers of all connecting users","By cloaking resources so unauthorized users cannot reach the app to inject scripts","It encrypts the DOM so injected scripts cannot read any of the page's contents"], correct:2, explanation:"SDP reduces exposure by hiding resources from unauthorized access; the distractors describe controls SDP does not perform." },
  { id:60544, domain:3, level:2, question:"How does SDP help mitigate brute-force login attempts against an exposed service?", options:["By cloaking resources so the service is hidden and attackers cannot reach the login","It locks every account after a single failed attempt regardless of the source address","It adds a mandatory thirty-second delay between all authentication attempts globally","It replaces passwords with biometrics that brute-force tools are unable to guess"], correct:0, explanation:"SDP reduces exposure by hiding resources from unauthorized access; the distractors describe controls SDP does not perform." },
  { id:60545, domain:3, level:2, question:"How does SDP help mitigate exploitation of a zero-day in an internet-facing service?", options:["It detects the zero-day using signatures that the vendor ships within minutes of discovery","By cloaking the service so it is not internet-facing and stays hidden until authorization","It sandboxes the exploit so it can run but cannot affect the underlying host system","It hot-patches the vulnerable function in memory before the exploit can trigger it"], correct:1, explanation:"SDP reduces exposure by hiding resources from unauthorized access; the distractors describe controls SDP does not perform." },
  { id:60546, domain:3, level:2, question:"How does SDP help mitigate credential stuffing using breached password lists?", options:["It compares each login against a list of every known breached password in real time","It forces all users onto passkeys so reused passwords become completely irrelevant","By cloaking resources so stolen passwords fail without an authorized device and host","It rate-limits the total number of logins the whole organization may perform per hour"], correct:2, explanation:"SDP reduces exposure by hiding resources from unauthorized access; the distractors describe controls SDP does not perform." },
  { id:60547, domain:3, level:2, question:"How does SDP help mitigate network reconnaissance and host enumeration?", options:["It floods scanners with thousands of fake hosts to overwhelm their enumeration logic","It detects scan patterns and alerts the SOC, which then manually blocks each source","It changes the subnet addressing scheme every hour to invalidate any captured map","By cloaking resources so hosts return nothing and the network map appears empty"], correct:3, explanation:"SDP reduces exposure by hiding resources from unauthorized access; the distractors describe controls SDP does not perform." },
  { id:60548, domain:3, level:2, question:"What happens at the SDP gateway when a valid SPA packet is received?", options:["A narrow, temporary path is opened so the authorized client can begin its handshake","The gateway permanently opens the service port for any client on that same subnet","The gateway forwards the packet's payload directly into the protected application","The gateway replies with the full list of services the client is allowed to use"], correct:0, explanation:"A valid SPA briefly opens a path for the authorized client only; it does not open the port broadly or leak service lists." },
  { id:60549, domain:3, level:2, question:"Why is SPA described as enabling a 'default-deny' service that appears closed?", options:["The service answers all probes but rejects data after the TCP handshake completes","No port responds until a valid single packet authorizes the specific requesting host","The service rotates its listening port so probes consistently hit a closed socket","The service replies only to packets that originate from inside the corporate LAN"], correct:1, explanation:"SPA keeps the port unresponsive until a valid packet arrives, so the service appears closed to everyone else." },
  { id:60550, domain:3, level:2, question:"Which property of SPA makes it lightweight compared to a full authentication exchange?", options:["It negotiates a session key across several round trips before sending any data","It downloads a policy bundle from the controller before each connection attempt","It conveys authorization in a single unsolicited packet without a prior handshake","It establishes a persistent control channel that must stay open for the session"], correct:2, explanation:"SPA uses one packet with no handshake, making it lightweight; multi-round-trip negotiation is the opposite." },
  { id:60551, domain:3, level:3, question:"An attacker captures an SDP client's SPA packet and resends it later. Why does it fail?", options:["The gateway has already permanently whitelisted the client, so the packet is ignored","The packet's HMAC is computed over the payload and never includes any timing data","The controller blocks the source IP after seeing two packets from the same address","Its embedded time-based value is now stale, so the gateway rejects the replayed packet"], correct:3, explanation:"SPA includes a time element so replays are stale and rejected; the HMAC alone would not stop replay without it." },
  { id:60552, domain:3, level:1, question:"A remote worker's laptop connects through an SDP gateway to an internal HR app. Which model is this?", options:["Client-to-gateway","Server-to-server, used for automated backend service communication","Gateway-to-gateway, used to bridge two physically separate sites","Client-to-server-to-client, used to connect two end-user devices"], correct:0, explanation:"A client reaching a resource via a protecting gateway is client-to-gateway." },
  { id:60553, domain:3, level:1, question:"Two microservices in different clusters authenticate to each other via SDP with no human involved. Which model?", options:["Client-to-gateway, where a user device reaches a protected application","Server-to-server","Gateway-to-gateway, where two whole networks are bridged together","Client-to-server-to-client, where two users are brokered together"], correct:1, explanation:"Automated service-to-service communication is the server-to-server model." },
  { id:60554, domain:3, level:1, question:"An SDP links a branch office network to headquarters with cloaking and per-flow authorization. Which model?", options:["Client-to-gateway, connecting a single endpoint to one resource","Server-to-server, securing two cooperating backend services","Gateway-to-gateway","Client-to-server-to-client, brokering a peer-to-peer user session"], correct:2, explanation:"Linking two networks via SDP gateways is the gateway-to-gateway model." },
  { id:60555, domain:3, level:2, question:"A help-desk agent remotely controls a user's workstation through an SDP broker without exposing ports. Which model?", options:["Client-to-gateway, where one client reaches one protected resource","Server-to-server, used only for backend machine-to-machine traffic","Gateway-to-gateway, used to bridge two corporate site networks","Client-to-server-to-client"], correct:3, explanation:"Brokering two user devices through an intermediary is client-to-server-to-client." },
  { id:60556, domain:3, level:2, question:"In which SDP model does an Accepting Host directly front the application server itself?", options:["Client-to-server, where the resource host runs the AH function itself","Gateway-to-gateway, where two separate networks are joined together","Client-to-server-to-client, where two human users are brokered together","Server-to-server, used purely for automated east-west service traffic"], correct:0, explanation:"In client-to-server the protected server itself performs the AH role rather than a separate gateway." },
  { id:60557, domain:3, level:2, question:"Which statement best contrasts SDP's access scope with a typical VPN's?", options:["SDP exposes the whole LAN, whereas a VPN restricts users to one application only","SDP exposes only authorized resources, whereas a VPN often grants broad network reach","SDP and a VPN both place the connected device onto an internal routable subnet","SDP requires a hardware concentrator, whereas a VPN can run purely in software"], correct:1, explanation:"SDP gives narrow per-resource access while VPNs typically grant broad network access." },
  { id:60558, domain:3, level:2, question:"Why can a compromised VPN endpoint be more dangerous than a compromised SDP client?", options:["The VPN endpoint always stores plaintext credentials that SDP clients never hold","The VPN endpoint cannot be revoked once issued, unlike an SDP client session","The VPN endpoint may have broad network access, enabling wide lateral movement","The VPN endpoint must run on hardware, so it cannot be isolated like software"], correct:2, explanation:"Broad VPN network access enables lateral movement; SDP confines each session to one resource." },
  { id:60559, domain:3, level:2, question:"How does SDP's connection model improve on a VPN's 'connect first, authenticate second' approach?", options:["SDP authenticates only after the user has fully loaded the target application","SDP skips authentication entirely once the device has been enrolled one time","SDP authenticates the network link but never the individual user behind it","SDP authenticates and authorizes before any network connectivity is established"], correct:3, explanation:"SDP requires pre-authentication and pre-authorization before connectivity, unlike connect-first VPNs." },
  { id:60560, domain:3, level:1, question:"ZTNA is best described as which of the following?", options:["A category of solutions providing identity-aware, per-application access to resources","A wide-area network protocol that replaces BGP for inter-site routing","A hardware firewall standard that defines stateful packet inspection rules","A cloud storage tier optimized for retaining long-term compliance archives"], correct:0, explanation:"ZTNA delivers identity-aware per-app access; the others are unrelated networking or storage concepts." },
  { id:60561, domain:3, level:2, question:"In service-initiated ZTNA, how does the application avoid inbound exposure?", options:["The application is published with a public IP but protected by a strong firewall rule","A connector inside the network dials out to the broker, so no inbound ports are opened","The broker scans the application hourly and patches any inbound port it discovers open","The application accepts inbound traffic only from a fixed list of partner IP ranges"], correct:1, explanation:"An outbound connector means no inbound ports are exposed; publishing a public IP would defeat that." },
  { id:60562, domain:3, level:2, question:"Why is endpoint-initiated ZTNA dependent on a device agent?", options:["The agent stores the application's data locally so the network link can be optional","The agent acts as the certificate authority issuing trust to all other endpoints","The agent originates and secures the connection and reports device posture to the broker","The agent replaces the broker by deciding policy directly on the user's device"], correct:2, explanation:"The agent initiates the secured connection and supplies posture; it is not a CA or policy decision point." },
  { id:60563, domain:3, level:2, question:"A vendor markets a ZTNA product built on SDP principles. What core behavior should it exhibit?", options:["Resources are publicly reachable but every session is logged for later auditing","All users receive a routable internal IP once their device has been registered","The product disables encryption internally to let inspection tools read traffic","Resources stay cloaked and access is granted only after identity and context checks"], correct:3, explanation:"SDP-based ZTNA cloaks resources and gates access on identity/context; public reachability or routable IPs contradict it." },
  { id:60564, domain:3, level:2, question:"Why must the SDP controller never be directly exposed to untrusted networks if avoidable?", options:["Its compromise undermines the entire trust model by letting attackers authorize access","It holds the only copy of application data, which would be lost if it were reached","It is the sole device performing encryption, so exposure decrypts all live sessions","It must remain offline at all times, so any network exposure breaks its core design"], correct:0, explanation:"Compromising the trust broker enables illicit authorization; it does not store app data or decrypt all sessions." },
  { id:60565, domain:3, level:2, question:"What is one architectural mitigation for protecting the SDP controller itself?", options:["Giving the controller a public IP so administrators can always reach it quickly","Placing the controller behind its own SPA-protected gateway so it is also cloaked","Disabling authentication on the controller to avoid lockouts during an incident","Running the controller and the AH on one host to reduce the attack surface count"], correct:1, explanation:"Cloaking the controller behind SPA protects it; a public IP or disabled auth would increase risk." },
  { id:60566, domain:3, level:2, question:"What does the SDP controller verify before instructing a gateway to accept a connection?", options:["Only that the destination application is currently online and accepting traffic","Both the requesting host's identity and its authorization for the target resource","Only the geographic region of the client to apply a regional pricing policy","Only that the gateway has spare capacity to handle one additional session"], correct:1, explanation:"The controller checks identity and authorization before programming the AH; capacity or geography are not the gate." },
  { id:60567, domain:3, level:2, question:"How does SDP relate to the principle of least privilege?", options:["It grants the maximum access by default and revokes it only upon detected misuse","It applies least privilege solely to administrators while users get broad access","It limits each authorized session to only the resources that principal truly needs","It enforces least privilege only at the application layer, not on the network"], correct:2, explanation:"SDP enforces least privilege on the network by exposing only needed resources per session." },
  { id:60568, domain:3, level:2, question:"How does SDP support micro-segmentation goals?", options:["By placing all workloads in one large flat VLAN that is easy to firewall as a unit","By tagging packets with VLAN IDs that switches use to separate user departments","By assigning each application a public subnet that is filtered at the edge router","By creating per-session, per-resource connections instead of broad network access"], correct:3, explanation:"SDP's per-session per-resource tunnels achieve fine-grained segmentation without flat networks or VLAN reliance." },
  { id:60569, domain:3, level:3, question:"An IH is authorized for application A but tries to reach application B on the same host. What happens?", options:["The attempt fails because authorization is scoped per resource, not per host","It succeeds because reaching one app on a host grants access to all its apps","It succeeds only if application B is listening on the same port as application A","It is queued until an administrator manually approves the additional application"], correct:0, explanation:"SDP authorization is per-resource, so access to A does not imply access to B even on the same host." },
  { id:60570, domain:3, level:1, question:"What is a key benefit of SDP for remote-access scenarios?", options:["Remote users gain full LAN access, which simplifies file-share discovery for them","Remote users reach only authorized apps without being placed on the corporate network","Remote users avoid all authentication once their home IP has been registered once","Remote users share a single pooled credential to reduce administrative overhead"], correct:1, explanation:"SDP gives remote users least-privilege app access without LAN exposure; the others weaken security." },
  { id:60571, domain:3, level:2, question:"Which outcome should an organization expect after replacing a broad VPN with SDP/ZTNA?", options:["A larger attack surface because more gateways are now exposed to the internet","The elimination of any need to authenticate users before granting connectivity","A smaller attack surface and tighter scoping of what each user can reach","A requirement that all users connect only from company-owned office locations"], correct:2, explanation:"SDP/ZTNA shrink the attack surface and scope access tightly; it does not remove authentication or require offices." },
  { id:60572, domain:3, level:2, question:"Why does SDP improve the experience of onboarding third-party contractors?", options:["Contractors receive full domain administrator rights to streamline their setup work","Contractors are placed on the internal network so they can self-discover resources","Contractors share a permanent VPN profile that never needs to be revoked later","Contractors can be granted access to just the specific apps they need, nothing more"], correct:3, explanation:"SDP scopes contractor access to specific apps; broad rights or network placement would over-grant." },
  { id:60573, domain:3, level:1, question:"What does 'resource cloaking' mean in the context of SDP?", options:["Making protected resources unresponsive and invisible to unauthorized clients","Encrypting resource names in DNS so only internal resolvers can decode them","Hiding resource logs from auditors unless they hold a special clearance level","Disguising one application as another to confuse any automated scanning tools"], correct:0, explanation:"Cloaking hides resources from unauthorized clients; it is not about DNS encryption or log access." },
  { id:60574, domain:3, level:1, question:"Which document defines the canonical SDP architecture and workflow used in this domain?", options:["The IETF TLS 1.3 protocol standard published in RFC 8446","The Cloud Security Alliance SDP specification","The NIST 800-53 catalog of federal security and privacy controls","The PCI DSS standard governing the handling of cardholder payment data"], correct:1, explanation:"The CSA SDP specification defines the architecture; the others are unrelated standards." },
  { id:60575, domain:3, level:2, question:"What is a primary reason SDP is considered an enabler of Zero Trust?", options:["It trusts any device inside the corporate firewall without further verification","It assumes the internal network is safe and applies controls only at the edge","It denies access by default and verifies identity and context before connecting","It grants broad access first and inspects traffic afterward for anomalies"], correct:2, explanation:"SDP's default-deny and verify-before-connect behavior aligns with Zero Trust; trusting internal traffic does not." },
  { id:60576, domain:3, level:2, question:"In SDP, why is device validation important in addition to user authentication?", options:["It replaces the need to authenticate the user once the device has been enrolled","It allows the controller to skip policy evaluation for previously seen devices","It lets the gateway accept any user as long as the device passed a one-time scan","It ensures a legitimate user is not connecting from a compromised or unknown device"], correct:3, explanation:"Device validation guards against compromised devices; it complements rather than replaces user authentication." },
  { id:60577, domain:3, level:3, question:"An organization wants services hidden from internet scanners yet reachable by authorized staff. Which SDP property delivers this?", options:["Cloaking combined with Single Packet Authorization gating access at the gateway","A geo-fence that blocks foreign IP addresses while permitting all domestic ones","A rotating DNS record that changes the service hostname several times per day","An allowlist of partner IP ranges maintained manually at the edge firewall"], correct:0, explanation:"Cloaking plus SPA hides services from scanners while admitting authorized staff; geo-fencing or DNS rotation does not cloak." },
  { id:60578, domain:3, level:2, question:"Which statement about SDP and encryption is accurate?", options:["SDP avoids encryption to keep latency low and relies on cloaking for confidentiality","SDP commonly uses mutual TLS to authenticate and encrypt the established connection","SDP encrypts only metadata while leaving the application payload in plaintext form","SDP delegates all encryption to the application, performing none at the gateway"], correct:1, explanation:"SDP typically secures connections with mutual TLS; it does not skip encryption or encrypt only metadata." },
  { id:60579, domain:3, level:1, question:"What is the main drawback of relying on a traditional perimeter firewall alone for access control?", options:["It encrypts internal traffic too aggressively for monitoring tools to inspect it","It forces every user to install a heavyweight agent before they can connect at all","Once inside the perimeter, an attacker can often move laterally with little resistance","It exposes no services externally, which prevents legitimate remote work entirely"], correct:2, explanation:"A flat perimeter permits lateral movement once breached; SDP addresses this with per-resource control." },
  { id:60580, domain:3, level:2, question:"Why does SDP conceptually separate authorization signaling from the data connection?", options:["So the data connection can be established before any authorization is evaluated","So multiple clients can share one authorization token to reduce controller load","So the controller can inspect the full application payload for malicious content","So the gateway can stay closed and only open for clients the controller has approved"], correct:3, explanation:"Separating authorization keeps the gateway closed until the controller approves a specific client." },
  { id:60581, domain:3, level:2, question:"What distinguishes SDP's approach from simply hiding services behind a NAT?", options:["SDP requires cryptographic authorization per client, not mere address translation","SDP and NAT both rely solely on private addressing to make services unreachable","SDP uses NAT internally but adds a public IP to every protected backend server","SDP depends on port forwarding rules that expose each service on a unique port"], correct:0, explanation:"SDP gates access with cryptographic authorization, unlike NAT which only translates addresses." },
  { id:60582, domain:3, level:1, question:"Which statement correctly describes the core goal of an SDP?", options:["Providing a faster content-delivery network for static web assets to end users","Restricting and cloaking resource access to authorized principals only","Serving as the organization's primary data-loss-prevention engine for files","Acting as the central log aggregator for all security telemetry across sites"], correct:1, explanation:"The correct statement reflects the established concept of the SDP definition; the distractors describe behaviors SDP does not exhibit." },
  { id:60583, domain:3, level:3, question:"An exam question asks about the behavior of an SDP gateway facing an unknown source. Which answer is correct?", options:["It returns a friendly error page explaining how to request access to the resource","It caches the request and serves it once the user authenticates at a later time","It silently discards the traffic and reveals nothing about the protected host","It forwards the request to a load balancer for distribution to backend peers"], correct:2, explanation:"The correct statement reflects the default-drop posture of SDP; the distractors describe behaviors SDP does not exhibit." },
  { id:60584, domain:3, level:1, question:"Select the option that best characterizes what Single Packet Authorization achieves.", options:["Authorizing a specific client before any service port becomes reachable","Compressing the TLS handshake into a single packet to cut connection latency","Limiting each session to transmitting only one packet of payload data total","Broadcasting the gateway's location to all clients on the local subnet quickly"], correct:0, explanation:"The correct statement reflects the purpose of SPA; the distractors describe behaviors SDP does not exhibit." },
  { id:60585, domain:3, level:2, question:"Which of the following accurately reflects the SDP controller's primary duty?", options:["Terminating user sessions and serving the protected application's web content","Authenticating hosts and authorizing which connections may be made","Storing the master copy of all protected data behind the accepting gateway","Scanning the perimeter for any ports that may have been left open by mistake"], correct:1, explanation:"The correct statement reflects the controller's trust-broker role; the distractors describe behaviors SDP does not exhibit." },
  { id:60586, domain:3, level:3, question:"When explaining the Accepting Host's primary duty to a colleague, which statement is right?", options:["Issuing time-based one-time passwords to every initiating host client device","Maintaining the authoritative directory of users and their assigned group roles","Admitting only connections that the controller has explicitly authorized","Performing deep packet inspection on all outbound internet traffic from users"], correct:2, explanation:"The correct statement reflects the AH role; the distractors describe behaviors SDP does not exhibit." },
  { id:60587, domain:3, level:1, question:"Which choice is the most accurate regarding the Initiating Host's primary duty?", options:["Hosting the protected application and accepting inbound user sessions directly","Brokering trust decisions between all other hosts in the deployment topology","Aggregating connection logs from every gateway for later compliance review","Authenticating to the controller and then connecting to authorized resources"], correct:3, explanation:"The correct statement reflects the IH role; the distractors describe behaviors SDP does not exhibit." },
  { id:60588, domain:3, level:1, question:"Which statement correctly describes the function of mutual TLS in an SDP session?", options:["Authenticating both endpoints and encrypting the connection between them","Authenticating only the server while trusting the connecting client implicitly","Encrypting just the first packet to keep the rest of the flow fast and light","Replacing the controller as the policy decision point for the active session"], correct:0, explanation:"The correct statement reflects how mTLS works in SDP; the distractors describe behaviors SDP does not exhibit." },
  { id:60589, domain:3, level:2, question:"An exam question asks about how SDP curbs lateral movement. Which answer is correct?", options:["Placing all clients on a shared subnet to make movement easier to watch","Confining each authorized session to a single resource rather than a network","Logging movement attempts but otherwise allowing them to proceed freely","Routing all internal traffic through the internet to slow attackers down"], correct:1, explanation:"The correct statement reflects how SDP limits lateral movement; the distractors describe behaviors SDP does not exhibit." },
  { id:60590, domain:3, level:3, question:"Select the option that best characterizes how SDP shrinks the attack surface.", options:["Consolidating all services onto a single internet-facing public address block","Publishing service banners that mislead attackers about the software in use","Hiding resources so unauthorized parties cannot even detect their presence","Increasing the number of open ports to spread out any incoming attack load"], correct:2, explanation:"The correct statement reflects how SDP reduces the attack surface; the distractors describe behaviors SDP does not exhibit." },
  { id:60591, domain:3, level:1, question:"Which of the following accurately reflects how SDP embodies Zero Trust?", options:["Trusting all devices located within the corporate network perimeter by default","Granting access first and revoking it only after detecting an anomaly later","Assuming the internal network is inherently safe from any compromise at all","Denying by default and verifying identity and context before connecting"], correct:3, explanation:"The correct statement reflects SDP's Zero Trust alignment; the distractors describe behaviors SDP does not exhibit." },
  { id:60592, domain:3, level:2, question:"When explaining the SDP black-cloud concept to a colleague, which statement is right?", options:["Resources are invisible and unreachable until a client has been authenticated","Resources are published openly so any client can discover them before login","Resources are stored encrypted at rest so theft of disks yields no plaintext","Resources are duplicated across regions so an outage never blocks access"], correct:0, explanation:"The black cloud hides resources until authentication; the distractors describe behaviors SDP does not exhibit." },
  { id:60593, domain:3, level:2, question:"Which choice is the most accurate regarding pre-authorization in SDP?", options:["Access is granted first and the principal is authorized only after the session ends","A principal must be authorized before any network path to a resource is opened","The controller pre-shares resource passwords so authorization can later be skipped","Resources stay open and authorization is reconstructed from logs after the fact"], correct:1, explanation:"Pre-authorization means approval precedes connectivity; the distractors describe behaviors SDP does not exhibit." },
  { id:60594, domain:3, level:2, question:"Which statement correctly describes the purpose of SPA's time-based element?", options:["It compresses authentication data so the packet fits within a single datagram","It encrypts the username so the gateway can recover it without a shared key","It makes captured packets stale so a later replay is rejected by the gateway","It signals the controller which application the client wishes to reach next"], correct:2, explanation:"The time element provides replay resistance; the distractors describe behaviors SPA does not provide." },
  { id:60595, domain:3, level:2, question:"An exam question asks which SDP component is the trust broker. Which answer is correct?", options:["The Accepting Host gateway that fronts and protects the target resource","The Initiating Host client that runs on the user's endpoint device","The directory service that stores user identities and their group roles","The controller, which authenticates hosts and authorizes connections"], correct:3, explanation:"The controller is the trust broker; the distractors are other roles in the architecture." },
  { id:60596, domain:3, level:2, question:"Select the option that best characterizes how SDP supports the cloud and hybrid model.", options:["It enforces identity-based access independent of where a workload happens to run","It requires every workload to reside in a single provider for the controller to work","It depends on static corporate IP ranges that cloud autoscaling keeps unchanged","It needs a dedicated hardware appliance installed in each cloud region to function"], correct:0, explanation:"SDP decouples access from network location, fitting cloud/hybrid; the distractors describe behaviors SDP does not exhibit." },
  { id:60597, domain:3, level:2, question:"Which of the following accurately reflects how SDP secures IoT endpoints?", options:["By assigning each device a public IP so it can be reached securely from anywhere","By cloaking constrained devices so they are not exposed to internet scanning","By requiring a heavyweight detection agent on every device regardless of its memory","By guaranteeing each device's firmware is patched before its traffic is permitted"], correct:1, explanation:"SDP cloaks IoT endpoints even when constrained; the distractors describe behaviors SDP does not provide." },
  { id:60598, domain:3, level:2, question:"When explaining how SDP differs from a VPN to a colleague, which statement is right?", options:["SDP requires hardware tokens for everyone while a VPN can use passwords alone","SDP works only in one data center while a VPN is designed for the public cloud","SDP grants per-resource access after authorization while a VPN often exposes a network","SDP uses weaker ciphers but offsets this with a much faster connection setup time"], correct:2, explanation:"SDP gives least-privilege per-resource access unlike broad VPN access; the distractors are false claims." },
  { id:60599, domain:3, level:2, question:"Which choice is the most accurate regarding service-initiated ZTNA?", options:["It always requires a heavy agent installed on every connecting user's device first","It keeps the application directly exposed to the public internet for performance","It can only be used for automated server-to-server machine-to-machine traffic","It uses an outbound connector from the app so no inbound ports are exposed"], correct:3, explanation:"Service-initiated ZTNA uses an outbound connector and is often agentless; the distractors are false." },
  { id:60600, domain:3, level:1, question:"Which statement correctly describes the SDP controller-to-AH step in the workflow?", options:["The controller instructs the AH to accept the specific authorized initiating host","The AH instructs the controller to push a full user list to every connected client","The AH opens all of its ports so the controller can verify the service is healthy","The controller forwards the client's password to the AH for a second verification"], correct:0, explanation:"The controller programs the AH to expect a named IH; the distractors describe behaviors SDP does not exhibit." },
  { id:60601, domain:3, level:2, question:"An exam question asks why the SDP controller must be hardened. Which answer is correct?", options:["Because it stores the only copy of all protected application data on disk","Because its compromise as the trust broker could authorize illicit connections","Because it performs all network encryption and its failure decrypts live sessions","Because it is the only device with a public IP so attackers reach it first"], correct:1, explanation:"A compromised trust broker can grant unauthorized access; the distractors misstate the controller's role." },
  { id:60602, domain:3, level:3, question:"Select the option that best characterizes SDP's default-drop posture.", options:["It permits all traffic until a rule explicitly blocks a known-malicious source","It accepts traffic for inspection while logging it for later forensic analysis","It denies and discards all traffic until access is explicitly authorized first","It redirects unknown traffic to a captive portal for self-service registration"], correct:2, explanation:"SDP is default-drop; the distractors describe allow, log, or redirect models SDP does not use." },
  { id:60603, domain:3, level:1, question:"Which of the following accurately reflects how an SDP gateway responds to an unauthorized probe?", options:["It returns a polite error message explaining how the sender can request access","It caches the probe and serves a response after the sender later authenticates","It forwards the probe to a load balancer for distribution to backend servers","It gives no response at all, so the host appears not to exist to the prober"], correct:3, explanation:"Silent non-response cloaks the host; the distractors would reveal the host's existence." },
  { id:60604, domain:3, level:2, question:"When explaining the Initiating Host's first action to a colleague, which statement is right?", options:["It authenticates to the controller before any path to a resource is created","It connects directly to the Accepting Host over an already-open service port","It contacts the target application server, which relays the request onward","It asks a peer Initiating Host to vouch for its new connection request"], correct:0, explanation:"The IH authenticates to the controller first; it cannot reach the AH until authorized." },
  { id:60605, domain:3, level:2, question:"Which choice is the most accurate regarding how SDP enforces least privilege?", options:["It assigns the broadest role first and trims unused permissions over time","It opens connectivity only to the specific resources a principal may use","It grants full subnet access but logs everything to detect misuse later on","It relies solely on the application to reject requests after network admission"], correct:1, explanation:"SDP limits network reachability to authorized resources; the distractors do not enforce least privilege at the network." },
  { id:60606, domain:3, level:2, question:"Which statement correctly describes the role of the Accepting Host gateway?", options:["It issues short-lived enrollment certificates to every new initiating host","It maintains the master directory of users along with their group memberships","It admits only connections that the controller has explicitly authorized","It performs deep inspection on all outbound internet traffic from clients"], correct:2, explanation:"The AH admits authorized IH connections; the distractors are other roles or unrelated functions." },
  { id:60607, domain:3, level:2, question:"An exam question asks how SDP reduces exposure to unpatched software. Which answer is correct?", options:["It automatically installs every vendor patch the moment it is released","It rewrites malicious payloads inline to neutralize known exploit signatures","It rebuilds each service in a fresh disposable container after every request","It makes the vulnerable service unreachable to anyone who cannot authenticate"], correct:3, explanation:"Cloaking keeps vulnerable services unreachable; SDP does not patch or rewrite payloads itself." },
  { id:60608, domain:3, level:2, question:"Select the option that best characterizes the client-to-gateway deployment model.", options:["An endpoint client reaching a protected resource through an Accepting Host gateway","Two protected networks joined together across an untrusted transit path","Two automated backend services exchanging east-west machine-to-machine traffic","Two human end-user devices brokered together through an intermediary node"], correct:0, explanation:"Client-to-gateway connects an IH client to an AH gateway; the others are different topologies." },
  { id:60609, domain:3, level:2, question:"Which of the following accurately reflects the server-to-server SDP model?", options:["A remote laptop reaching an internal application through a protecting gateway","Two automated services authenticating to each other for east-west traffic","Two whole corporate site networks being bridged over a shared backbone","Two end-user devices being brokered together through a central intermediary"], correct:1, explanation:"Server-to-server secures automated service-to-service traffic; the others involve users or networks." },
  { id:60610, domain:3, level:1, question:"When explaining SPA replay resistance to a colleague, which statement is right?", options:["A time-based value makes captured packets stale so replays are rejected","Two layers of encryption with controller-only keys block any replay attempt","A client-side proof-of-work puzzle must be solved before each packet is sent","A full mutual-TLS handshake must complete before the packet is transmitted"], correct:0, explanation:"A time element gives replay resistance; the distractors are not how SPA resists replay." },
  { id:60611, domain:3, level:2, question:"Which choice is the most accurate regarding the gateway-to-gateway model?", options:["It connects a single endpoint client to one specific protected resource only","It joins two networks like a site-to-site tunnel but adds cloaking and authorization","It secures two cooperating backend services exchanging automated API traffic","It brokers a peer-to-peer session between two separate end-user devices"], correct:1, explanation:"Gateway-to-gateway links two networks with SDP cloaking; the distractors are other models." },
  { id:60612, domain:3, level:1, question:"Which statement correctly describes resource cloaking in SDP?", options:["Making protected resources unresponsive and invisible to unauthorized clients","Encrypting resource hostnames in DNS so only internal resolvers can read them","Hiding resource access logs from auditors lacking a special clearance level","Disguising one application as a different one to confuse automated scanners"], correct:0, explanation:"Cloaking hides resources from unauthorized clients; the distractors describe unrelated behaviors." },
  { id:60613, domain:3, level:2, question:"An exam question asks how mutual TLS defends against man-in-the-middle attacks. Which answer is correct?", options:["It pins the session to one physical switch port no other device may use","Both endpoints verify each other's certificates, blocking middle-party impersonation","It encrypts only the handshake and leaves the application data in cleartext","It relays traffic through three nodes so no single node sees the full path"], correct:1, explanation:"Mutual certificate verification blocks impersonation; the distractors are unrelated to SDP's MITM defense." },
  { id:60614, domain:3, level:3, question:"Select the option that best characterizes the relationship between SDP and ZTNA.", options:["ZTNA is an older protocol that SDP was created to deprecate and replace","SDP and ZTNA are competing standards that cannot coexist in one deployment","SDP is a foundational architecture that ZTNA solutions commonly implement","ZTNA is a hardware product category while SDP is only a billing model"], correct:2, explanation:"ZTNA builds on SDP concepts; they are complementary, not competing or hardware-only." },
  { id:60615, domain:3, level:1, question:"Which of the following accurately reflects how SDP enforces pre-authentication?", options:["A user receives temporary access and is verified only after the session ends","The controller pre-shares all resource passwords so authentication is skipped","Resources stay open while authentication is reconstructed from logs afterward","A host must prove its identity before any path to a resource is established"], correct:3, explanation:"Pre-authentication means identity is proven before connectivity; the distractors contradict this." },
  { id:60616, domain:3, level:2, question:"When explaining why SDP curbs lateral movement to a colleague, which statement is right?", options:["Each authorized session reaches only its one resource, not the wider network","All clients share a single subnet so any movement is easier to monitor centrally","Internal encryption is disabled so monitoring tools can read all packet contents","Connections are routed over the internet to add geographic separation for safety"], correct:0, explanation:"Per-resource sessions block lateral movement; a shared subnet or disabled encryption would not." },
  { id:60617, domain:3, level:2, question:"Which choice is the most accurate regarding endpoint-initiated ZTNA?", options:["It keeps the application directly exposed to the public internet at all times","A device agent originates the secured connection and reports posture to the broker","It can be used only for automated server-to-server machine-to-machine traffic","The agent itself becomes the certificate authority issuing trust to all peers"], correct:1, explanation:"The agent initiates the connection and supplies posture; the distractors misstate its function." },
  { id:60618, domain:3, level:2, question:"Which statement correctly describes the SDP IH-to-controller step?", options:["The IH opens all of its local ports so the controller can probe its health","The IH broadcasts its identity to every gateway before contacting the controller","The IH authenticates to the controller, which then evaluates its authorization","The IH sends its credentials straight to the resource, which forwards them on"], correct:2, explanation:"The IH authenticates to the controller, which authorizes it; the distractors break the workflow." },
  { id:60619, domain:3, level:2, question:"An exam question asks how SDP mitigates port scanning. Which answer is correct?", options:["It randomizes the listening port every few seconds to outpace any scanner","It returns deliberately false banners to mislead and exhaust scanning tools","It rate-limits each scanning source until that scan eventually times out","Cloaked hosts never reply to unauthorized probes, so scanners find nothing"], correct:3, explanation:"Silent non-response defeats scanners; the distractors still reveal that something exists." },
  { id:60620, domain:3, level:1, question:"Select the option that best characterizes the SDP definition of a controller.", options:["The trust broker that authenticates hosts and authorizes their connections","The gateway that terminates traffic and forwards cleartext to the backend","The store that holds the only authoritative copy of each protected resource","The scanner that continuously hunts the internet for the company's open ports"], correct:0, explanation:"The controller is the trust broker; the distractors misstate its role." },
  { id:60621, domain:3, level:2, question:"Which of the following accurately reflects how SDP handles a stolen credential?", options:["It revokes any credential the instant it is offered for sale on the dark web","Valid credentials still fail without an authorized device and host posture","It encrypts stored passwords so a breached database yields no usable secrets","It forces an automatic password change after every single successful login"], correct:1, explanation:"Device-bound access defeats stolen credentials alone; the distractors are separate controls." },
  { id:60622, domain:3, level:3, question:"When explaining SDP micro-segmentation to a colleague, which statement is right?", options:["It places all workloads in one flat VLAN that can be firewalled as a unit","It tags packets with VLAN IDs so switches separate user departments cleanly","It creates per-session, per-resource connections instead of broad network access","It assigns each application a public subnet filtered only at the edge router"], correct:2, explanation:"SDP achieves segmentation via per-session per-resource tunnels; the distractors rely on flat or VLAN models." },
  { id:60623, domain:3, level:1, question:"Which choice is the most accurate regarding what a valid SPA packet triggers?", options:["The gateway permanently opens its service port to that entire client subnet","The gateway forwards the SPA payload straight into the protected application","The gateway replies with a full list of services the client may now use","The gateway opens a narrow temporary path so the client can start its handshake"], correct:3, explanation:"A valid SPA opens a narrow path for the authorized client; the distractors over-expose or leak data." },
  { id:60624, domain:3, level:2, question:"Which statement correctly describes how SDP reduces SQL injection exposure at the network layer?", options:["Only authorized clients can reach the application to attempt any injection","It parses every SQL statement and rejects queries that change multiple rows","It substitutes a read-only database copy to block all write-oriented attacks","It strips all user-supplied input before requests reach the application tier"], correct:0, explanation:"SDP limits who can send requests; it is not a WAF that parses SQL or strips input." },
  { id:60625, domain:3, level:2, question:"An exam question asks what device validation adds to user authentication in SDP. Which answer is correct?", options:["It removes the need to authenticate the user after the device is enrolled once","It ensures a legitimate user is not connecting from a compromised or unknown device","It lets the controller skip policy evaluation for devices it has already seen","It admits any user provided the device passed a single one-time posture scan"], correct:1, explanation:"Device validation guards against compromised devices; it complements, not replaces, user authentication." },
  { id:60626, domain:3, level:2, question:"Select the option that best characterizes how SDP/ZTNA compares to a VPN concentrator.", options:["They require users to be on-site before any remote tunnel can be established","They expose the same broad network but only add stronger encryption ciphers","They grant per-application access and cloak resources instead of network placement","They remove all authentication because the tunnel itself is treated as identity"], correct:2, explanation:"SDP/ZTNA give cloaked per-app access unlike broad VPNs; the distractors are false." },
  { id:60627, domain:3, level:2, question:"Which of the following accurately reflects the SDP controller-to-AH instruction?", options:["The controller tells the AH to broadcast its presence to all nearby clients","The controller tells the AH to open every port for a controller health check","The controller tells the AH to relay client credentials back for re-verification","The controller tells the AH to accept the one specific authorized initiating host"], correct:3, explanation:"The controller programs the AH to expect a named IH; the distractors defeat cloaking or misroute credentials." },
  { id:60628, domain:3, level:2, question:"When explaining how SDP mitigates denial-of-service to a colleague, which statement is right?", options:["Unauthenticated packets are dropped at the gateway before reaching the app","The application is mirrored across regions so attack traffic spreads out evenly","The ISP is asked to blackhole the attacker's prefix within a few seconds","All legitimate users are throttled equally to keep total load constant"], correct:0, explanation:"Dropping unauthorized traffic at the perimeter blocks floods; SDP is not a CDN or ISP blackhole." },
  { id:60629, domain:3, level:2, question:"Which choice is the most accurate regarding the SDP IH-to-AH connection?", options:["It is established before the controller has evaluated the host's authorization","It occurs only after the controller has authorized and programmed the gateway","It is created by the AH broadcasting itself so the IH can discover and join it","It bypasses the controller entirely once the two hosts exchange certificates"], correct:1, explanation:"The IH-to-AH tunnel forms only after controller authorization; the distractors break the workflow." },
  { id:60630, domain:3, level:3, question:"Which statement correctly describes how SDP shrinks the attack surface?", options:["By consolidating every service onto one internet-facing public address block","By publishing service banners that mislead attackers about the software in use","By hiding resources so unauthorized parties cannot even detect their presence","By increasing open ports to spread out the impact of any incoming attack"], correct:2, explanation:"Hiding resources reduces the attack surface; the distractors describe behaviors SDP does not exhibit." },
  { id:60631, domain:3, level:1, question:"An exam question asks what 'black cloud' means in SDP. Which answer is correct?", options:["A cloud region reserved only for storing encrypted security audit logs","A standby data center that activates only after the primary fully fails over","A quarantine segment for devices that failed their security posture checks","Infrastructure that is invisible and unreachable until a client authenticates"], correct:3, explanation:"The black cloud hides resources until authentication; the distractors describe unrelated infrastructure." },
  { id:60632, domain:3, level:2, question:"Select the option that best characterizes the SDP definition of cloaking benefits.", options:["Unauthorized parties cannot detect or connect to a resource that is hidden","All resource data is encrypted at rest so disk theft yields no plaintext","Resources are duplicated across regions so a single outage cannot block them","Resource hostnames are encrypted in DNS so only internal resolvers see them"], correct:0, explanation:"Cloaking hides resources from unauthorized parties; the distractors are unrelated controls." },
  { id:60633, domain:3, level:2, question:"Which of the following accurately reflects SDP's pre-authorization principle?", options:["A user is granted access first and authorized only after the transfer ends","A principal must be authorized before any path to a resource is opened","The controller pre-shares resource passwords so authorization is later skipped","Resources stay open and authorization is rebuilt from logs after the fact"], correct:1, explanation:"Pre-authorization requires approval before connectivity; the distractors contradict the model." },
  { id:60634, domain:3, level:2, question:"When explaining the controller's verification step to a colleague, which statement is right?", options:["It checks only whether the destination application is currently online","It checks only the client's region to apply a regional pricing policy","It verifies both the host's identity and its authorization for the resource","It checks only whether the gateway has spare capacity for one more session"], correct:2, explanation:"The controller checks identity and authorization; capacity and geography are not the gate." },
  { id:60635, domain:3, level:2, question:"Which choice is the most accurate regarding how SDP suits remote access?", options:["Remote users gain full LAN access to simplify discovering internal file shares","Remote users skip all authentication once their home IP is registered once","Remote users share one pooled credential to cut administrative overhead","Remote users reach only authorized apps without being placed on the network"], correct:3, explanation:"SDP gives least-privilege remote app access; the distractors weaken security." },
  { id:60636, domain:3, level:2, question:"Which statement correctly describes the SDP controller's exposure risk?", options:["As trust broker, its compromise could let an attacker authorize illicit access","It stores all application data, so its loss would erase every protected app","It performs all encryption, so its failure would decrypt all live sessions","It is the only device with a public IP, so attackers always reach it first"], correct:0, explanation:"A compromised trust broker can authorize illicit access; the distractors misstate the controller's role." },
  { id:60637, domain:3, level:2, question:"An exam question asks what mutual TLS provides after SPA. Which answer is correct?", options:["It lets the server skip verifying the client since SPA already proved identity","It encrypts only the server-to-client direction to protect downloaded data","It authenticates both endpoints and encrypts the established connection","It replaces the controller so the hosts can negotiate policy themselves"], correct:2, explanation:"mTLS authenticates both ends and encrypts the link after SPA; the distractors are incorrect." },
  { id:60638, domain:3, level:2, question:"Select the option that best characterizes how SDP enforces least privilege.", options:["It grants the broadest role by default and trims permissions over time","It applies least privilege to administrators while users keep broad access","It opens connectivity only to the resources a principal is authorized to use","It enforces least privilege at the application layer but not the network"], correct:2, explanation:"SDP limits network reachability to authorized resources; the distractors do not enforce it at the network." },
  { id:60639, domain:3, level:2, question:"Which of the following accurately reflects SDP's default-drop behavior?", options:["It permits traffic until a rule explicitly blocks a known-bad source address","It accepts traffic for inspection while logging it for later review only","It redirects unknown traffic to a captive portal for self-service signup","It denies and discards everything until access is explicitly authorized"], correct:3, explanation:"SDP is default-drop; the distractors describe allow, log, or redirect models SDP does not use." },
  { id:60640, domain:3, level:1, question:"When explaining the Accepting Host to a colleague, which statement is right?", options:["It is the gateway that admits only connections the controller authorized","It is the directory holding all user password hashes and group memberships","It is the client agent on a laptop that requests access to a resource","It is the appliance that issues short-lived certificates to new devices"], correct:0, explanation:"The AH admits authorized IH connections; the distractors are other roles." },
  { id:60641, domain:3, level:2, question:"Which choice is the most accurate regarding how SDP embodies Zero Trust?", options:["It trusts every device located inside the corporate firewall by default","It denies access by default and verifies identity and context before connecting","It grants broad access first and inspects traffic afterward for anomalies","It assumes the internal network is inherently safe from any compromise"], correct:1, explanation:"SDP's default-deny and verify-before-connect align with Zero Trust; the distractors contradict it." },
  { id:60642, domain:3, level:3, question:"Which statement correctly describes the purpose of Single Packet Authorization?", options:["It compresses an entire authentication handshake into one packet for speed","It limits a session to a single packet of application data for rate control","It authorizes a specific client before any service port becomes reachable","It bundles all session keys into one packet that the controller stores"], correct:2, explanation:"SPA authorizes a client before any port opens; the distractors misstate its purpose." },
  { id:60643, domain:3, level:1, question:"An exam question asks which component initiates an SDP access request. Which answer is correct?", options:["The Accepting Host gateway that guards the requested resource directly","The controller that brokers trust across the whole deployment topology","The logging collector that aggregates all connection telemetry centrally","The Initiating Host client running on the user's endpoint device"], correct:3, explanation:"The IH client initiates access; the AH and controller play other roles." },
  { id:60644, domain:3, level:2, question:"Select the option that best characterizes the client-to-server-to-client model.", options:["Two end-user devices brokered through an intermediary with no direct ports","A user device reaching a database that then replicates to a second database","Two gateways each shielding a different subnet of internal application servers","A client reaching an external SaaS that proxies onward to a partner network"], correct:0, explanation:"Client-to-server-to-client brokers two peer clients; the distractors are other topologies." },
  { id:60645, domain:3, level:2, question:"Which of the following accurately reflects how SDP mitigates credential theft impact?", options:["It revokes any credential the moment it appears for sale on the dark web","Valid credentials still fail without an authorized device and host posture","It encrypts stored passwords so a database breach yields no usable secrets","It forces an automatic password change after every single successful login"], correct:1, explanation:"Device-bound access defeats stolen credentials; the distractors are separate controls." },
  { id:60646, domain:3, level:2, question:"When explaining the SDP workflow order to a colleague, which statement is right?", options:["The IH reaches the AH first, then the AH asks the controller for approval","The AH contacts the controller first, which pushes a user list to each IH","Onboarding, then IH-to-controller, then controller-to-AH, then IH-to-AH","The IH-to-AH and controller-to-IH steps happen at the same time concurrently"], correct:2, explanation:"This is the correct CSA sequence; the distractors reverse or collapse the steps." },
  { id:60647, domain:3, level:2, question:"Which choice is the most accurate regarding SDP and the VPN attack surface?", options:["SDP exposes the whole LAN while a VPN restricts users to one app each","SDP and a VPN both place the connected device onto a routable internal subnet","SDP requires a hardware concentrator while a VPN runs purely in software","SDP exposes only authorized resources while a VPN often grants broad reach"], correct:3, explanation:"SDP gives narrow per-resource access; broad LAN exposure is the VPN trait." },
  { id:60648, domain:3, level:2, question:"Which statement correctly describes how SPA appears to an external scanner?", options:["The port appears closed because no response is sent until a valid packet arrives","The port answers all probes but rejects data after the handshake completes","The port rotates constantly so probes consistently hit a different closed socket","The port replies only to packets that originate from inside the corporate LAN"], correct:0, explanation:"SPA keeps the port unresponsive until a valid packet; the distractors still reveal a host." },
  { id:60649, domain:3, level:2, question:"An exam question asks how SDP curbs zero-day exploitation of an exposed service. Which answer is correct?", options:["It detects the zero-day with signatures the vendor ships within minutes","The service is no longer exposed because it stays hidden until authorization","It sandboxes the exploit so it runs but cannot affect the underlying host","It hot-patches the vulnerable function in memory before the exploit triggers"], correct:1, explanation:"Cloaking removes internet exposure; SDP does not rely on signatures or sandboxing for this." },
  { id:60650, domain:3, level:3, question:"Select the option that best characterizes the SDP controller's trust-broker function.", options:["It terminates all encrypted traffic and forwards cleartext to the backend app","It holds the only authoritative copy of every protected resource behind it","It authenticates hosts and decides which connections are permitted to occur","It scans the public internet for any of the company's exposed open ports"], correct:2, explanation:"The controller is the trust broker authorizing connections; the distractors misstate its role." },
  { id:60651, domain:3, level:1, question:"Which of the following accurately reflects how SDP suits cloud and hybrid setups?", options:["It requires all workloads in one provider to keep the controller logic simple","It depends on fixed corporate IP ranges that autoscaling reliably preserves","It needs a hardware appliance in every cloud region to terminate the tunnels","It enforces identity-based access independent of network location or perimeter"], correct:3, explanation:"SDP decouples access from location, fitting cloud/hybrid; the distractors are false constraints." },
  { id:60652, domain:3, level:2, question:"When explaining the Initiating Host role to a colleague, which statement is right?", options:["It is the client that authenticates to the controller then connects to resources","It is the server endpoint that hosts the protected business application itself","It is the broker that evaluates policy and signs each authorized session token","It is the logging service that records every connection attempt for auditing"], correct:0, explanation:"The IH is the requesting client; the distractors are other roles." },
  { id:60653, domain:3, level:2, question:"Which choice is the most accurate regarding the SDP IH-to-controller step?", options:["The IH opens all of its local ports so the controller can probe its health","The IH authenticates to the controller, which then evaluates its authorization","The IH broadcasts its identity to every gateway before contacting the controller","The IH sends credentials straight to the resource, which forwards them onward"], correct:1, explanation:"The IH authenticates to the controller, which authorizes it; the distractors break the workflow." },
  { id:60654, domain:3, level:2, question:"Which statement correctly describes how SDP defends against man-in-the-middle attacks?", options:["It pins the session to one physical switch port no other device may use","It encrypts only the handshake and leaves the application data in cleartext","Mutual TLS lets both endpoints verify certificates, blocking impersonation","It relays traffic through three nodes so no single node sees the full path"], correct:2, explanation:"Mutual certificate verification blocks impersonation; the distractors are unrelated." },
  { id:60655, domain:3, level:2, question:"An exam question asks what 'pre-authentication' means in SDP. Which answer is correct?", options:["A user is granted temporary access and verified only after the transfer ends","The controller pre-shares resource passwords so authentication is later skipped","Resources stay open while authentication is reconstructed from logs afterward","A host must prove its identity before any path to a resource is established"], correct:3, explanation:"Pre-authentication means identity is proven before connectivity; the distractors contradict it." },
  { id:60656, domain:3, level:2, question:"Select the option that best characterizes how an SDP gateway treats an unknown source.", options:["It silently discards the traffic and reveals nothing about the protected host","It returns a friendly page explaining how the sender can request access","It caches the request and serves it after the sender later authenticates","It forwards the request to a load balancer for distribution to peers"], correct:0, explanation:"Silent non-response cloaks the host; the distractors would reveal its existence." },
  { id:60657, domain:3, level:2, question:"Which of the following accurately reflects the SDP server-to-server use case?", options:["A remote laptop reaching an internal application through a protecting gateway","Two automated services authenticating to each other for east-west traffic","Two corporate site networks being bridged together over a shared backbone","Two end-user devices brokered together through a central intermediary node"], correct:1, explanation:"Server-to-server secures automated service-to-service traffic; the others involve users or networks." },
  { id:60658, domain:3, level:2, question:"When explaining mutual TLS in SDP to a colleague, which statement is right?", options:["It authenticates only the server while trusting the connecting client by default","It encrypts just the first packet to keep the rest of the flow fast and light","It authenticates both endpoints and encrypts the connection between them","It replaces the controller as the policy decision point for the session"], correct:2, explanation:"mTLS authenticates both ends and encrypts the link; the distractors are incorrect." },
  { id:60659, domain:3, level:2, question:"Which choice is the most accurate regarding how SDP limits lateral movement?", options:["It places all clients on a shared subnet so movement is easier to monitor","It logs movement attempts but otherwise allows them to proceed freely","It routes all internal traffic over the internet to slow down attackers","Each authorized session reaches only its one resource, not the wider network"], correct:3, explanation:"Per-resource sessions block lateral movement; the distractors do not prevent it." },
  { id:60660, domain:3, level:1, question:"Which statement correctly describes the purpose of resource cloaking?", options:["Making protected resources unresponsive and invisible to unauthorized clients","Encrypting resource hostnames in DNS so only internal resolvers can read them","Hiding resource logs from auditors who lack a special clearance level","Disguising one application as another to confuse automated scanning tools"], correct:0, explanation:"Cloaking hides resources from unauthorized clients; the distractors are unrelated behaviors." },
  { id:60661, domain:3, level:2, question:"An exam question asks how service-initiated ZTNA avoids inbound exposure. Which answer is correct?", options:["The application is published with a public IP behind a strong firewall rule","A connector inside the network dials out to the broker, opening no inbound ports","The broker scans the app hourly and patches any inbound port it discovers","The app accepts inbound traffic only from a fixed list of partner IP ranges"], correct:1, explanation:"An outbound connector means no inbound ports are exposed; publishing a public IP defeats that." },
  { id:60662, domain:3, level:3, question:"Select the option that best characterizes the SDP definition of its primary purpose.", options:["Caching application responses at edge nodes to accelerate web traffic","Replacing the identity provider by issuing its own long-lived access tokens","Restricting access to authorized principals while hiding resources from others","Encrypting data on application servers using rotating symmetric session keys"], correct:2, explanation:"SDP restricts and cloaks resource access; the distractors are unrelated functions." },
  { id:60663, domain:3, level:1, question:"Which of the following accurately reflects how SDP treats an unauthorized probe?", options:["It returns a polite error message explaining how to request resource access","It caches the probe and serves a response once the sender authenticates later","It forwards the probe to a load balancer for distribution to backend servers","It gives no response so the host appears not to exist to the prober"], correct:3, explanation:"Silent non-response cloaks the host; the distractors reveal its existence." },
  { id:60664, domain:3, level:2, question:"When explaining the SPA technique to a colleague, which statement is right?", options:["One authenticated packet authorizes a client before any service port opens","An entire handshake is compressed into one packet purely to save bandwidth","Each session is limited to a single packet of application data for rate control","All of a session's keys are bundled into one packet the controller stores"], correct:0, explanation:"SPA authorizes a client with one packet before any port opens; the distractors misstate it." },
  { id:60665, domain:3, level:2, question:"Which choice is the most accurate regarding the SDP controller's hardening?", options:["It can safely use a public IP since administrators must always reach it fast","It can be placed behind its own SPA-protected gateway so it is also cloaked","It should disable authentication to avoid lockouts during an active incident","It should be co-located on the same host as the AH to reduce attack surface"], correct:1, explanation:"Cloaking the controller behind SPA protects it; a public IP or disabled auth raises risk." },
  { id:60666, domain:3, level:2, question:"Which statement correctly describes how SDP applies least privilege?", options:["It assigns the broadest role first and trims unused permissions over time","It applies least privilege only to administrators while users get broad access","It opens connectivity only to the specific resources a principal may use","It enforces least privilege at the application layer but not the network"], correct:2, explanation:"SDP limits network reachability to authorized resources; the distractors do not." },
  { id:60667, domain:3, level:2, question:"An exam question asks what device validation adds in SDP. Which answer is correct?", options:["It removes the need to authenticate the user after one device enrollment","It lets the controller skip policy evaluation for previously seen devices","It admits any user provided the device passed a single posture scan once","It ensures a legitimate user is not connecting from a compromised device"], correct:3, explanation:"Device validation guards against compromised devices; it complements user authentication." },
  { id:60668, domain:3, level:2, question:"Select the option that best characterizes how SPA resists replay.", options:["A time-based value makes captured packets stale so a later replay is rejected","Two encryption layers with controller-only keys prevent any replay attempt","A client-side proof-of-work puzzle must be solved before each packet is sent","A full mutual-TLS handshake must complete before the packet is transmitted"], correct:0, explanation:"A time element gives replay resistance; the distractors are not how SPA resists replay." },
  { id:60669, domain:3, level:2, question:"Which of the following accurately reflects the gateway-to-gateway model?", options:["It connects a single endpoint client to one specific protected resource","It joins two networks like a site-to-site tunnel but adds cloaking and authorization","It secures two backend services exchanging automated east-west API traffic","It brokers a peer-to-peer session between two separate end-user devices"], correct:1, explanation:"Gateway-to-gateway links two networks with SDP cloaking; the distractors are other models." },
  { id:60670, domain:3, level:3, question:"When explaining SDP's core purpose to a colleague, which statement is right?", options:["It caches application responses at edge nodes to speed up web delivery","It replaces the identity provider by minting its own long-lived tokens","It encrypts server data at rest using rotating provider-managed keys","It restricts resource access to authorized principals and hides the rest"], correct:3, explanation:"SDP restricts and cloaks resource access; the distractors are unrelated functions." },
  { id:60671, domain:3, level:1, question:"Which choice is the most accurate regarding the SDP definition of an Accepting Host?", options:["The gateway protecting resources that admits only authorized initiating hosts","The directory that stores all user password hashes and group memberships","The client agent on a laptop that originates the request for a resource","The appliance that issues short-lived certificates to newly enrolled devices"], correct:0, explanation:"The AH admits authorized IH connections; the distractors are other roles." },
  { id:60672, domain:3, level:2, question:"Which statement correctly describes the SDP IH-to-AH connection timing?", options:["It is established before the controller has evaluated the host's authorization","It occurs only after the controller authorizes and programs the gateway","It is created by the AH broadcasting itself so the IH can find and join","It bypasses the controller entirely once the hosts exchange certificates"], correct:1, explanation:"The IH-to-AH tunnel forms only after controller authorization; the distractors break the workflow." },
  { id:60673, domain:3, level:2, question:"How does an SDP architecture help mitigate volumetric denial-of-service against protected services?", options:["It absorbs all attack traffic at the application server with extra CPU capacity","Unauthorized traffic is dropped at the gateway before reaching the hidden service","It returns detailed error pages so attackers voluntarily stop their flood","It reroutes every request through a single chokepoint that scales infinitely"], correct:1, explanation:"Default-drop gateways discard unauthorized traffic before it reaches the service; the distractors fail to protect the backend." },
  { id:60674, domain:3, level:3, question:"Select the option that best characterizes how SDP differs from a VPN.", options:["SDP requires hardware tokens for all users while a VPN uses passwords alone","SDP works only in a single data center while a VPN targets the public cloud","SDP grants per-resource access after authorization while a VPN exposes a network","SDP uses weaker ciphers but offsets this with faster initial connection setup"], correct:2, explanation:"SDP gives least-privilege per-resource access; the distractors are false claims about SDP." },
  { id:60675, domain:3, level:2, question:"During SDP onboarding, how does a new initiating host first establish trust with the controller?", options:["It broadcasts an open discovery request to every gateway on the network until one finally answers","It is pre-provisioned with credentials and authenticates to the controller before any access","It connects directly to the protected resource and negotiates trust in-band","It waits for the accepting host to push a one-time trust token to it"], correct:1, explanation:"An IH is pre-provisioned and must authenticate to the controller first; the distractors bypass the controller or break cloaking." },
  { id:60676, domain:3, level:2, question:"When explaining the default-drop posture to a colleague, which statement is right?", options:["The gateway denies and discards all traffic until access is explicitly authorized","The gateway permits traffic until a rule explicitly blocks a known-bad source","The gateway accepts traffic for inspection while logging it for later review","The gateway redirects unknown traffic to a captive portal for self-service"], correct:0, explanation:"SDP is default-drop; the distractors describe allow, log, or redirect models SDP does not use." },
  { id:60677, domain:3, level:2, question:"Which statement best describes service-initiated (cloud-initiated) ZTNA?", options:["The protected application is published directly to the public internet by default","A connector inside the network dials outbound to the broker, avoiding inbound ports","Each end user must run a local certificate authority to join the service","It supports only on-premises resources and cannot reach cloud-hosted apps"], correct:1, explanation:"Service-initiated ZTNA uses an outbound connector so no inbound ports are exposed; the distractors describe exposure or false limitations." },
  { id:60678, domain:3, level:2, question:"How does Single Packet Authorization help SDP resist replay attacks?", options:["It allows any repeated packet through so long as the source IP is unchanged","It includes time-based and counter values so a captured packet cannot be reused","It encrypts the entire session before the first packet is ever transmitted","It relies on the gateway broadcasting a fresh shared password each minute"], correct:1, explanation:"SPA packets embed time/counter and HMAC data so replays are rejected; the distractors would permit reuse or break cloaking." },
  { id:60679, domain:3, level:2, question:"An exam question asks how SDP reduces exposure to OWASP web threats. Which answer is correct?", options:["It inspects HTTP bodies and rewrites every request to a safe canonical form","It auto-generates a patch for each OWASP category as soon as one is published","It blocks the app from making outbound calls that could leak sensitive data","Fewer attackers can reach the app because resources stay cloaked from them"], correct:3, explanation:"SDP reduces exposure by hiding resources; the distractors describe controls SDP does not perform." },
  { id:60680, domain:3, level:1, question:"Select the option that best characterizes the SDP definition of an Initiating Host.", options:["The client that authenticates to the controller then connects to resources","The server endpoint that hosts the protected business application itself","The broker that evaluates policy and signs each authorized session token","The logging service that records every connection attempt for auditing"], correct:0, explanation:"The IH is the requesting client; the distractors are other roles." },
  { id:60681, domain:3, level:2, question:"Which of the following accurately reflects how SDP supports micro-segmentation?", options:["It places all workloads in one flat VLAN firewalled together as a single unit","It creates per-session, per-resource connections instead of broad network access","It tags packets with VLAN IDs so switches separate user departments cleanly","It assigns each application a public subnet filtered only at the edge router"], correct:1, explanation:"SDP segments via per-session per-resource tunnels; the distractors rely on flat or VLAN models." },
  { id:60682, domain:3, level:3, question:"When explaining the SDP black-cloud property to a colleague, which statement is right?", options:["Resources are published openly so any client can discover them before login","Resources are stored encrypted at rest so theft of disks yields no plaintext","Resources are invisible and unreachable until a client has been authenticated","Resources are duplicated across regions so an outage never blocks any access"], correct:2, explanation:"The black cloud hides resources until authentication; the distractors are unrelated behaviors." },
  { id:60683, domain:3, level:1, question:"Which choice is the most accurate regarding how a valid SPA packet is handled?", options:["The gateway permanently opens its service port to the client's entire subnet","The gateway forwards the SPA payload directly into the protected application","The gateway replies with the full list of services the client may now use","The gateway opens a narrow temporary path so the client can begin its handshake"], correct:3, explanation:"A valid SPA opens a narrow path for the authorized client; the distractors over-expose or leak data." },
  { id:60684, domain:3, level:2, question:"Which statement correctly describes how SDP suits remote access?", options:["Remote users reach only authorized apps without being placed on the network","Remote users gain full LAN access to simplify discovering internal file shares","Remote users skip authentication once their home IP has been registered","Remote users share a pooled credential to reduce administrative overhead"], correct:0, explanation:"SDP gives least-privilege remote app access; the distractors weaken security." },
  { id:60685, domain:3, level:2, question:"An exam question asks what distinguishes service-initiated ZTNA. Which answer is correct?", options:["It always requires a heavy agent on every user's device before connecting","It uses an outbound app connector and needs no agent on the endpoint","It keeps the application directly exposed to the public internet for speed","It can only be used for automated server-to-server machine traffic"], correct:1, explanation:"Service-initiated ZTNA uses an outbound connector and is often agentless; the distractors are false." },
  { id:60686, domain:3, level:2, question:"Select the option that best characterizes how SDP enforces pre-authorization.", options:["A principal must be authorized before any path to a resource is opened","A user is granted access first and authorized only after the transfer ends","The controller pre-shares resource passwords so authorization is later skipped","Resources stay open while authorization is rebuilt from logs afterward"], correct:0, explanation:"Pre-authorization requires approval before connectivity; the distractors contradict the model." },
  { id:60687, domain:3, level:2, question:"In an SDP gateway-to-gateway deployment model, what is connected through the authorized tunnel?", options:["A single end-user laptop reaching one specific cloud application instance","Two networks or server groups linked so authorized systems communicate across them","A controller replicating its policy database to a standby controller node","An external auditor granted read-only visibility into all network traffic"], correct:1, explanation:"Gateway-to-gateway joins two networks/server groups over an authorized path; the distractors describe other models or unrelated functions." },
  { id:60688, domain:3, level:2, question:"When explaining how SDP mitigates brute-force logins to a colleague, which statement is right?", options:["The login is hidden behind cloaking, so attackers cannot reach it to try guesses","Every account locks after a single failed attempt regardless of the source","A mandatory thirty-second delay is added between all login attempts globally","Passwords are replaced with biometrics that brute-force tools cannot guess"], correct:0, explanation:"Cloaking hides the login from attackers; the distractors describe controls SDP does not perform." },
  { id:60689, domain:3, level:2, question:"Which choice is the most accurate regarding how SDP/ZTNA compares to a VPN concentrator?", options:["They require users to be on-site before any remote tunnel is established","They grant per-application access and cloak resources rather than network placement","They expose the same broad network but only add stronger encryption ciphers","They remove all authentication because the tunnel itself is treated as identity"], correct:1, explanation:"SDP/ZTNA give cloaked per-app access unlike broad VPNs; the distractors are false." },
  { id:60690, domain:3, level:3, question:"Which statement correctly describes the controller's verification before authorizing a connection?", options:["It checks only whether the destination application is currently online","It checks only the client's region to apply a regional pricing policy","It verifies both the requesting host's identity and its authorization","It checks only whether the gateway has spare capacity for one session"], correct:2, explanation:"The controller checks identity and authorization; capacity and geography are not the gate." },
  { id:60691, domain:3, level:1, question:"An exam question asks how SDP shrinks the attack surface. Which answer is correct?", options:["By consolidating every service onto one internet-facing public address block","By publishing misleading service banners about the software actually in use","By increasing open ports to spread out the impact of any incoming attack","By hiding resources so unauthorized parties cannot even detect their presence"], correct:3, explanation:"Hiding resources reduces the attack surface; the distractors describe behaviors SDP does not exhibit." },
  { id:60692, domain:3, level:2, question:"Select the option that best characterizes the SDP IH-to-controller authentication step.", options:["The IH authenticates to the controller before any path to a resource exists","The IH opens all of its local ports so the controller can probe its health","The IH broadcasts its identity to every gateway before reaching the controller","The IH sends credentials straight to the resource, which forwards them onward"], correct:0, explanation:"The IH authenticates to the controller first; the distractors break the workflow." },
  { id:60693, domain:3, level:2, question:"Which of the following accurately reflects the client-to-gateway deployment model?", options:["Two protected networks joined together across an untrusted transit path","An endpoint client reaching a protected resource through an Accepting Host gateway","Two automated backend services exchanging east-west machine-to-machine traffic","Two human end-user devices brokered together through an intermediary node"], correct:1, explanation:"Client-to-gateway connects an IH client to an AH gateway; the others are different topologies." },
  { id:60694, domain:3, level:2, question:"When explaining the role of mutual TLS after SPA to a colleague, which statement is right?", options:["It lets the server skip verifying the client since SPA already proved identity","It encrypts only the server-to-client direction to protect downloaded data","It authenticates both endpoints and encrypts the established connection","It replaces the controller so the hosts negotiate policy directly themselves"], correct:2, explanation:"mTLS authenticates both ends and encrypts the link after SPA; the distractors are incorrect." },
  { id:60695, domain:3, level:2, question:"Which choice is the most accurate regarding the SDP controller's exposure risk?", options:["It stores all application data, so its loss would erase every protected app","It performs all encryption, so its failure would decrypt every live session","It is the only device with a public IP, so attackers always reach it first","As trust broker, its compromise could let an attacker authorize illicit access"], correct:3, explanation:"A compromised trust broker can authorize illicit access; the distractors misstate the controller's role." },
  { id:60696, domain:3, level:2, question:"Which statement correctly describes how SDP applies the least-privilege principle?", options:["It opens connectivity only to the resources a principal is authorized to use","It assigns the broadest role first and trims unused permissions over time","It applies least privilege to administrators while users keep broad access","It enforces least privilege at the application layer but not the network"], correct:0, explanation:"SDP limits network reachability to authorized resources; the distractors do not enforce it at the network." },
  { id:60697, domain:3, level:2, question:"An exam question asks what TOTP contributes to SPA. Which answer is correct?", options:["A static API key in the client binary that is rotated only once a year","A time-based code from a shared secret that adds replay resistance to SPA","A nonce the server must email the user before each new connection attempt","A permanent hardware-printed code that never changes for the device's life"], correct:1, explanation:"TOTP supplies the time-varying value used in SPA; static or permanent codes give no replay resistance." },
  { id:60698, domain:3, level:2, question:"Select the option that best characterizes how SDP treats device posture.", options:["It validates the device so a legitimate user is not connecting from a compromised one","It ignores the device once the user has authenticated with a valid password","It checks only the device MAC address and the destination server's load","It admits any device that has connected successfully at least once before"], correct:0, explanation:"Device posture validation complements user authentication; the distractors weaken or ignore it." },
  { id:60699, domain:3, level:2, question:"Which of the following accurately reflects how SDP curbs lateral movement?", options:["It places all clients on a shared subnet so movement is easier to monitor","It logs movement attempts but otherwise allows them to proceed freely","It routes all internal traffic over the internet to slow down attackers","Each authorized session reaches only its one resource, not the wider network"], correct:3, explanation:"Per-resource sessions block lateral movement; the distractors do not prevent it." },
  { id:60700, domain:3, level:2, question:"Which statement correctly describes how SDP reduces the network attack surface overall?", options:["It hides resources so unauthorized parties cannot even detect their presence","It consolidates every service onto a single internet-facing public address","It publishes misleading service banners about the software actually running","It increases the number of open ports to spread out any incoming attack"], correct:0, explanation:"Hiding resources reduces the attack surface; the distractors describe behaviors SDP does not exhibit." }
];
